FUNCTION_BLOCK StackMin
VAR_INPUT
    push : BOOL;
    pop : BOOL;
    reset : BOOL;
END_VAR
VAR_OUTPUT
    error : BOOL;
    status : WORD;
END_VAR
VAR_IN_OUT
    item : INT;
    stack : ARRAY[0..3] OF INT;
END_VAR
VAR
    top : INT := -1; // Tracks the index of the top element; -1 means empty
    i : INT; // Loop variable
    minIndex : INT; // Index of minimum value
    minValue : INT; // Minimum value
END_VAR

// Reset handling - highest priority
IF reset THEN
    top := -1;
    error := FALSE;
    status := 16#0000;

// Push operation - next priority
ELSIF push THEN
    IF top >= 3 THEN
        // Stack is full
        error := TRUE;
        status := 16#8A04;
    ELSE
        // Perform push
        top := top + 1;
        stack[top] := item;
        error := FALSE;
        status := 16#0000;
    END_IF;

// Pop operation - lowest priority
ELSIF pop THEN
    IF top < 0 THEN
        // Stack is empty
        error := TRUE;
        status := 16#8A05;
    ELSE
        // Find minimum value and its index
        minIndex := 0;
        minValue := stack[0];

        i := 1;
        WHILE i <= top DO
            IF stack[i] < minValue THEN
                minValue := stack[i];
                minIndex := i;
            END_IF;
            i := i + 1;
        END_WHILE;

        // Store minimum value in output
        item := minValue;

        // Shift elements down to remove the minimum element
        i := minIndex;
        WHILE i < top DO
            stack[i] := stack[i + 1];
            i := i + 1;
        END_WHILE;

        // Decrement top
        top := top - 1;

        error := FALSE;
        status := 16#0000;
    END_IF;

// No operation
ELSE
    // Keep current state
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK FloatingAverage
VAR_INPUT
    cyclicExecution : BOOL;
    trigger : BOOL;
    value : REAL;
    windowSize : INT;
    reset : BOOL;
END_VAR
VAR_OUTPUT
    average : REAL;
    windowSizeReached : BOOL;
    error : BOOL;
    status : WORD;
END_VAR
VAR
    dataBuffer : ARRAY[1..100] OF REAL;
    bufferIndex : INT := 1;
    sum : REAL := 0.0;
    prevTrigger : BOOL := FALSE;
    i : INT;
END_VAR

// Handle reset condition
IF reset THEN
    // Clear data buffer
    FOR i := 1 TO 100 DO
        dataBuffer[i] := 0.0;
    END_FOR;

    // Reset internal variables
    bufferIndex := 1;
    sum := 0.0;

    // Reset outputs
    average := 0.0;
    windowSizeReached := FALSE;
    error := FALSE;
    status := 16#0000;

    // Skip further processing in this cycle after reset
    RETURN;
END_IF;

// Validate windowSize
IF (windowSize < 1) OR (windowSize > 100) THEN
    error := TRUE;
    status := 16#8200;
    // Maintain current outputs when error occurs
    RETURN;
ELSE
    error := FALSE;
    status := 16#0000;
END_IF;

// Determine if new data should be processed
IF cyclicExecution THEN
    // Process new data every cycle
    // Continue with calculation
ELSIF trigger AND NOT prevTrigger THEN
    // Process new data on rising edge of trigger
    // Continue with calculation
ELSE
    // No new data to process, maintain current state
    prevTrigger := trigger;
    RETURN;
END_IF;

// Store previous trigger state for edge detection
prevTrigger := trigger;

// Store new value in buffer
dataBuffer[bufferIndex] := value;

// Update sum based on whether window is full
IF windowSizeReached THEN
    // Buffer is full, replace oldest value
    // Calculate index of oldest value (next position will be overwritten)
    IF bufferIndex = 1 THEN
        sum := sum - dataBuffer[windowSize] + value;
    ELSE
        sum := sum - dataBuffer[bufferIndex - 1] + value;
    END_IF;
ELSE
    // Buffer is not full yet, just add new value
    sum := sum + value;
END_IF;

// Update buffer index
bufferIndex := bufferIndex + 1;

// Check if window size has been reached
IF bufferIndex > windowSize THEN
    bufferIndex := 1;
    windowSizeReached := TRUE;
END_IF;

// Calculate average
IF windowSizeReached THEN
    average := sum / windowSize;
ELSE
    // Use current number of elements in buffer
    average := sum / (bufferIndex - 1);
END_IF;

END_FUNCTION_BLOCK

