        CASE channel_measuringMode[i] OF
            0:  (* Non-temperature measurement *)
                (* Validate scaling limits *)
                IF hiLimit <= loLimit THEN
                    (* Error: Invalid scaling limits *)
                    channel_retVal[i] := 16#8002;
                    CONTINUE;  (* Skip to next channel *)
                END_IF;

