    OutFlowRate1 := PrelimOut1;
END_IF;

// Limit OutFlowRate2 to range 0-100
IF PrelimOut2 < 0.0 THEN
    OutFlowRate2 := 0.0;
ELSIF PrelimOut2 > 100.0 THEN
    OutFlowRate2 := 100.0;
ELSE
    OutFlowRate2 := PrelimOut2;
END_IF;

