    TurnTimerSeconds : INT; (* Timer for egg turning cycle in seconds *)
    StartButtonPrev : BOOL; (* Previous state of StartButton for edge detection *)
    bInitialized : BOOL; (* Flag to track initialization *)
END_VAR

(* Initialization *)
