VAR_OUTPUT
    TrafficLight1 : BOOL; (* Output for traffic light at intersection 1 *)
    TrafficLight2 : BOOL; (* Output for traffic light at intersection 2 *)
    TrafficLight3 : BOOL; (* Output for traffic light at intersection 3 *)
    TrafficLight4 : BOOL; (* Output for traffic light at intersection 4 *)
END_VAR

VAR
    // No internal variables needed for this simple comparison logic
END_VAR

// Process first pair: Intersection 1 and Intersection 2
IF VehicleCount1 > VehicleCount2 THEN
    TrafficLight1 := TRUE;
    TrafficLight2 := FALSE;
ELSIF VehicleCount2 > VehicleCount1 THEN
    TrafficLight1 := FALSE;
    TrafficLight2 := TRUE;
ELSE
    // Equal counts: default priority to first intersection (Intersection 1)
    TrafficLight1 := TRUE;
    TrafficLight2 := FALSE;
END_IF;

// Process second pair: Intersection 3 and Intersection 4
IF VehicleCount3 > VehicleCount4 THEN
    TrafficLight3 := TRUE;
    TrafficLight4 := FALSE;
ELSIF VehicleCount4 > VehicleCount3 THEN
    TrafficLight3 := FALSE;
    TrafficLight4 := TRUE;
ELSE
    // Equal counts: default priority to first intersection (Intersection 3)
    TrafficLight3 := TRUE;
    TrafficLight4 := FALSE;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK HomeBrewingSystem
VAR_INPUT
    TemperatureSensor : REAL; (* Input for temperature measurement (°C) *)
    WaterFlowSensor : REAL; (* Input for water flow measurement (L/min) *)
    BrewingStartTime : TIME; (* Input for brewing process start time *)
    BrewingDuration : TIME; (* Input for total brewing duration *)
END_VAR
VAR_OUTPUT
    HeatingElement : BOOL; (* Output to control heating element *)
    AgitationMotor : BOOL; (* Output to control agitation motor *)
    HopsDispenser : BOOL; (* Output to control hops dispenser *)
    FermentationTank : BOOL; (* Output to control fermentation tank *)
END_VAR
VAR
    bHopsDispensed : BOOL; (* Internal flag for hops dispenser *)
    bTankTransferred : BOOL; (* Internal flag for fermentation tank *)
    tElapsedTime : TIME; (* Internal variable for elapsed brewing time *)
    tCurrentTime : TIME; (* Internal variable for current time *)
    tFiveHours : TIME := T#5h; (* Constant for 5 hours *)
    tFortyEightHours : TIME := T#48h; (* Constant for 48 hours *)
    bFirstScan : BOOL := TRUE; (* First scan detection flag *)
    tPrevStartTime : TIME; (* Previous brewing start time for change detection *)
END_VAR

(* Initialization and reset logic *)
IF bFirstScan THEN
    bFirstScan := FALSE;
    bHopsDispensed := FALSE;
    bTankTransferred := FALSE;
    HeatingElement := FALSE;
    AgitationMotor := FALSE;
    HopsDispenser := FALSE;
    FermentationTank := FALSE;
    tPrevStartTime := BrewingStartTime;
END_IF

(* Check if brewing start time has changed - reset flags if changed *)
IF BrewingStartTime <> tPrevStartTime THEN
    bHopsDispensed := FALSE;
    bTankTransferred := FALSE;
    HopsDispenser := FALSE;
    FermentationTank := FALSE;
    tPrevStartTime := BrewingStartTime;
END_IF

(* Get current time and calculate elapsed brewing time *)
tCurrentTime := TIME();
tElapsedTime := tCurrentTime - BrewingStartTime;

(* Ensure elapsed time is not negative *)
IF tElapsedTime < T#0s THEN
    tElapsedTime := T#0s;
END_IF

(* Temperature control logic *)
IF TemperatureSensor < 65.0 THEN
    HeatingElement := TRUE;
ELSE
    HeatingElement := FALSE;
END_IF

(* Agitation motor control logic *)
IF WaterFlowSensor > 0.5 THEN
    AgitationMotor := TRUE;
ELSE
    AgitationMotor := FALSE;
END_IF

(* Hops dispensing logic *)
IF (tElapsedTime >= tFiveHours) AND (NOT bHopsDispensed) THEN
    HopsDispenser := TRUE;
    bHopsDispensed := TRUE;
END_IF

(* Fermentation tank transfer logic *)
IF (tElapsedTime >= tFortyEightHours) AND (NOT bTankTransferred) THEN
    FermentationTank := TRUE;
    bTankTransferred := TRUE;
END_IF

END_FUNCTION_BLOCK

FUNCTION_BLOCK MultimediaArtInstallationControl
VAR_INPUT
    MotionSensor : BOOL; (* Motion detection input *)
    AudioTrack : BOOL; (* Selected audio track *)
    VisualContent : BOOL; (* Selected visual content *)
END_VAR
VAR_OUTPUT
    LightingControl : BOOL; (* Lighting control output *)
    AudioControl : BOOL; (* Audio playback control *)
    VisualControl : BOOL; (* Visual display control *)
END_VAR
VAR
    ActivationTimer : INT; (* Timer for activation duration *)
    bPrevMotionState : BOOL; (* Previous motion sensor state for edge detection *)
    bIsActiveState : BOOL; (* Current state flag: TRUE=Active, FALSE=Idle *)
    iScanCounter : INT; (* Counter for timer increments *)
    iTimerLimit : INT := 300; (* Predefined timer limit in seconds *)
END_VAR

(* Initialization and state management *)
IF NOT bPrevMotionState THEN
    (* First scan or reset condition *)
    LightingControl := FALSE;
    AudioControl := FALSE;
    VisualControl := FALSE;
    ActivationTimer := 0;
    bIsActiveState := FALSE;
    iScanCounter := 0;
END_IF

(* State transition logic *)
IF MotionSensor AND NOT bPrevMotionState THEN
    (* Rising edge detection - transition from Idle to Active *)
    bIsActiveState := TRUE;
    ActivationTimer := 0;
    iScanCounter := 0;
ELSIF NOT MotionSensor AND bPrevMotionState THEN
    (* Falling edge detection - transition from Active to Idle *)
    bIsActiveState := FALSE;
    ActivationTimer := 0;
    iScanCounter := 0;
END_IF

(* Active State Logic *)
IF bIsActiveState THEN
    (* Activate multimedia elements *)
    LightingControl := TRUE;
    AudioControl := AudioTrack;
    VisualControl := VisualContent;

    (* Timer increment logic - increment every second *)
    iScanCounter := iScanCounter + 1;

    (* Assuming 100ms scan cycle, increment timer every 10 cycles (1 second) *)
    IF iScanCounter >= 10 THEN
        ActivationTimer := ActivationTimer + 1;
        iScanCounter := 0;

        (* Check timer limit - safety timeout *)
        IF ActivationTimer >= iTimerLimit THEN
            bIsActiveState := FALSE;
            ActivationTimer := 0;
        END_IF;
    END_IF;
ELSE
    (* Idle State Logic *)
    LightingControl := FALSE;
    AudioControl := FALSE;
    VisualControl := FALSE;
    ActivationTimer := 0;
    iScanCounter := 0;
END_IF

(* Store current motion state for next scan *)
bPrevMotionState := MotionSensor;

END_FUNCTION_BLOCK

FUNCTION_BLOCK CapsuleFillingMachineControl
VAR_INPUT
    CapsuleWeight : REAL; (* Current capsule weight *)
    TargetWeight : REAL; (* Target weight to achieve *)
    CapsuleInPosition : BOOL; (* Capsule position sensor *)
    HopperEmpty : BOOL; (* Hopper empty sensor *)
END_VAR
VAR_OUTPUT
    FeederMotor : BOOL; (* Feeder motor control *)
    FillingMotor : BOOL; (* Filling motor control *)
    ConveyorMotor : BOOL; (* Conveyor motor control *)
    FillingInProgress : BOOL; (* Filling status *)
END_VAR
VAR
    // State machine states
    CurrentState : INT := 0; // 0=IDLE, 1=CONVEYING, 2=FILLING, 3=CONVEYING_OUT, 4=ERROR
    PreviousState : INT := 0;

    // Timers
    ConveyorTimer : TON;
    FillingTimer : TON;
    ConveyOutTimer : TON;

    // Timer presets (in milliseconds)
    ConveyorTimePreset : TIME := T#2S;
    FillingTimePreset : TIME := T#10S;
    ConveyOutTimePreset : TIME := T#1S;

    // PID controller variables
    PID_Error : REAL := 0.0;
    PID_LastError : REAL := 0.0;
    PID_Integral : REAL := 0.0;
    PID_Derivative : REAL := 0.0;
    PID_Output : REAL := 0.0;

    // PID tuning parameters
    Kp : REAL := 1.0; // Proportional gain
    Ki : REAL := 0.1; // Integral gain
    Kd : REAL := 0.05; // Derivative gain

    // Weight tolerance
    WeightTolerance : REAL := 0.005; // 0.5% tolerance

    // Error flags
    ErrorCode : INT := 0; // 0=No error, 1=Hopper empty, 2=Capsule not detected, 3=Filling timeout, 4=Initial overfill

    // Internal flags
    CapsuleDetected : BOOL := FALSE;
    WeightReached : BOOL := FALSE;
    ManualReset : BOOL := FALSE;

    // Cycle time tracking
    LastCycleTime : TIME := T#0s;
    DeltaTime : REAL := 0.01; // Default 10ms cycle time

    // Low hopper warning
    LowHopperWarning : BOOL := FALSE;
    LowHopperThreshold : REAL := 0.1; // 10% of normal level (simulated)

    // Internal variables for state transitions
    StateEntryTime : TIME := T#0s;
    CurrentTime : TIME := T#0s;
END_VAR

VAR_TEMP
    // Temporary variables for calculations
    TempReal : REAL;
    TempBool : BOOL;
    i : INT;
END_VAR

// Main execution
// Calculate delta time for PID controller
CurrentTime := TIME();
IF LastCycleTime > T#0s THEN
    DeltaTime := TIME_TO_REAL(CurrentTime - LastCycleTime); // Convert to seconds
    IF DeltaTime > 1.0 THEN
        DeltaTime := 0.01; // Limit maximum delta time
    END_IF
    IF DeltaTime < 0.001 THEN
        DeltaTime := 0.001; // Limit minimum delta time
    END_IF
END_IF
LastCycleTime := CurrentTime;

// Safety Check (Hopper Empty) - Highest priority
IF HopperEmpty THEN
    // Immediate shutdown
    FeederMotor := FALSE;
    FillingMotor := FALSE;
    ConveyorMotor := FALSE;
    FillingInProgress := FALSE;
    CurrentState := 4; // ERROR state
    ErrorCode := 1; // Hopper empty error
    RETURN; // Terminate execution
END_IF

// Check for low hopper level (simulated - would normally come from sensor)
// For simulation, we'll assume LowHopperWarning is an external input
// If LowHopperWarning is TRUE, we can set a warning but continue operation
// Only transition to error if it becomes critical

// State machine execution
CASE CurrentState OF
    0: // IDLE state
        // Reset outputs
        FeederMotor := FALSE;
        FillingMotor := FALSE;
        ConveyorMotor := FALSE;
        FillingInProgress := FALSE;

        // Reset error code if no active error
        IF ErrorCode <> 0 AND ManualReset THEN
            ErrorCode := 0;
            ManualReset := FALSE;
        END_IF

        // Weight Validation (Initial Check)
        IF CapsuleWeight >= TargetWeight THEN
            // Avoid overfilling
            CurrentState := 4; // ERROR state
            ErrorCode := 4; // Initial overfill error
        ELSIF CapsuleInPosition AND ErrorCode = 0 THEN
            // Capsule detected and no errors
            // Start conveying
            CurrentState := 1; // CONVEYING state
            StateEntryTime := CurrentTime;

            // Reset timers
            ConveyorTimer(IN:=FALSE, PT:=ConveyorTimePreset);
            ConveyorTimer(IN:=TRUE, PT:=ConveyorTimePreset);
        END_IF

    1: // CONVEYING state
        // Activate conveyor motor
        ConveyorMotor := TRUE;
        FillingInProgress := FALSE;

        // Check for capsule not detected timeout
        ConveyorTimer(IN:=TRUE, PT:=ConveyorTimePreset);
        IF ConveyorTimer.Q THEN
            // Timer expired - capsule not detected in time
            CurrentState := 4; // ERROR state
            ErrorCode := 2; // Capsule not detected error
            ConveyorMotor := FALSE;
        ELSIF CapsuleInPosition THEN
            // Capsule reached position - transition to FILLING
            CurrentState := 2; // FILLING state
            StateEntryTime := CurrentTime;
            ConveyorMotor := FALSE;

            // Reset filling timer
            FillingTimer(IN:=FALSE, PT:=FillingTimePreset);
            FillingTimer(IN:=TRUE, PT:=FillingTimePreset);

            // Reset PID controller
            PID_LastError := 0.0;
            PID_Integral := 0.0;
            PID_Derivative := 0.0;
        END_IF

    2: // FILLING state
        // Set filling in progress flag
        FillingInProgress := TRUE;

        // Activate feeder motor
        FeederMotor := TRUE;

        // Implement PID control for filling motor
        // Calculate error
        PID_Error := TargetWeight - CapsuleWeight;

        // Check if weight reached target within tolerance
        IF ABS(PID_Error) <= (TargetWeight * WeightTolerance) THEN
            // Weight reached - stop filling
            FillingMotor := FALSE;
            FeederMotor := FALSE;
            CurrentState := 3; // CONVEYING_OUT state
            StateEntryTime := CurrentTime;

            // Reset conveyor out timer
            ConveyOutTimer(IN:=FALSE, PT:=ConveyOutTimePreset);
            ConveyOutTimer(IN:=TRUE, PT:=ConveyOutTimePreset);
        ELSE
            // Continue filling with PID control
            // Calculate integral term with anti-windup
            IF NOT (FillingMotor AND (PID_Output >= 1.0)) THEN
                PID_Integral := PID_Integral + (PID_Error * DeltaTime);
            END_IF

            // Calculate derivative term
            PID_Derivative := (PID_Error - PID_LastError) / DeltaTime;

            // Calculate PID output
            PID_Output := (Kp * PID_Error) + (Ki * PID_Integral) + (Kd * PID_Derivative);

            // Limit output to 0-1 range
            IF PID_Output > 1.0 THEN
                PID_Output := 1.0;
            ELSIF PID_Output < 0.0 THEN
                PID_Output := 0.0;
            END_IF

            // Control filling motor based on PID output
            // Use threshold to convert to BOOL output
            IF PID_Output > 0.1 THEN
                FillingMotor := TRUE;
            ELSE
                FillingMotor := FALSE;
            END_IF

            // Update last error
            PID_LastError := PID_Error;

            // Check for filling timeout
            FillingTimer(IN:=TRUE, PT:=FillingTimePreset);
            IF FillingTimer.Q THEN
                // Filling timeout
                FillingMotor := FALSE;
                FeederMotor := FALSE;
                CurrentState := 4; // ERROR state
                ErrorCode := 3; // Filling timeout error
            END_IF
        END_IF

    3: // CONVEYING_OUT state
        // Activate conveyor to move filled capsule out
        ConveyorMotor := TRUE;
        FillingInProgress := FALSE;
        FeederMotor := FALSE;
        FillingMotor := FALSE;

        // Check timer
        ConveyOutTimer(IN:=TRUE, PT:=ConveyOutTimePreset);
        IF ConveyOutTimer.Q THEN
            // Conveying complete
            ConveyorMotor := FALSE;
            CurrentState := 0; // Return to IDLE
        END_IF

    4: // ERROR state
        // Deactivate all motors
        FeederMotor := FALSE;
        FillingMotor := FALSE;
        ConveyorMotor := FALSE;
        FillingInProgress := FALSE;

        // Stay in error state until manual reset
        IF ManualReset THEN
            // Reset error if conditions allow
            IF NOT HopperEmpty AND CapsuleWeight < TargetWeight THEN
                CurrentState := 0; // Return to IDLE
                ErrorCode := 0;
                ManualReset := FALSE;
            END_IF
        END_IF

    ELSE
        // Invalid state - reset to IDLE
        CurrentState := 0;
END_CASE

// Store previous state for edge detection
PreviousState := CurrentState;
END_FUNCTION_BLOCK

FUNCTION_BLOCK AmusementRideControl
VAR_INPUT
    StartButton : BOOL;    (* Start button input *)
    StopButton : BOOL;     (* Emergency stop button input *)
    SpeedSensor : REAL;    (* Speed sensor input (RPM) *)
    SafetySensor : BOOL;   (* Safety sensor status *)
END_VAR
VAR_OUTPUT
    MotorOn : BOOL := FALSE;    (* Motor control output *)
    BrakeOn : BOOL := TRUE;     (* Brake control output *)
END_VAR
VAR
    SpeedLimit : REAL := 60.0;  (* Maximum allowed speed in RPM *)
END_VAR

    (* Emergency Stop - Highest Priority *)
    IF StopButton THEN
        MotorOn := FALSE;
        BrakeOn := TRUE;
    ELSE
        (* Start Condition - All conditions must be met *)
        IF StartButton AND (NOT StopButton) AND (SpeedSensor <= SpeedLimit) AND SafetySensor THEN
            MotorOn := TRUE;
            BrakeOn := FALSE;
        ELSE
            MotorOn := FALSE;
            BrakeOn := TRUE;
        END_IF;

        (* Normal Operation Safety Monitoring *)
        IF MotorOn THEN
            IF (SpeedSensor > SpeedLimit) OR (NOT SafetySensor) THEN
                MotorOn := FALSE;
                BrakeOn := TRUE;
            END_IF;
        END_IF;
    END_IF;

    (* Default State - Fail-Safe *)
    IF NOT MotorOn THEN
        BrakeOn := TRUE;
    END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK ShredderControl
VAR_INPUT
    StartButton : BOOL; (* Input for the start button *)
    StopButton : BOOL; (* Input for the stop button *)
    EmergencyStop : BOOL; (* Input for the emergency stop button *)
    MotorStatus : BOOL; (* Feedback status of the shredder motor *)
    MaterialInFeed : BOOL; (* Input for material being fed into the shredder *)
    JammedSensor : BOOL; (* Input for detecting material jamming *)
END_VAR
VAR_OUTPUT
    MotorControl : BOOL; (* Output for controlling the shredder motor *)
    SafetyRelay : BOOL; (* Output for safety relay: TRUE=Safe, FALSE=Unsafe *)
END_VAR
VAR
    bMotorRunning : BOOL; (* Internal flag for motor running state *)
    bEmergencyCondition : BOOL; (* Internal flag for emergency condition *)
    bStartButtonPrev : BOOL; (* Previous state of StartButton for edge detection *)
    bStopButtonPrev : BOOL; (* Previous state of StopButton for edge detection *)
    bStartRisingEdge : BOOL; (* Moved from local VAR block inside code *)
    bStopRisingEdge : BOOL;  (* Moved from local VAR block inside code *)
END_VAR

(* Initialize outputs and internal variables *)
MotorControl := FALSE;
SafetyRelay := FALSE;
bMotorRunning := FALSE;
bEmergencyCondition := FALSE;
bStartButtonPrev := FALSE;
bStopButtonPrev := FALSE;
bStartRisingEdge := FALSE;
bStopRisingEdge := FALSE;

(* Check for emergency conditions - highest priority *)
IF EmergencyStop OR JammedSensor THEN
    bEmergencyCondition := TRUE;
    MotorControl := FALSE;
    SafetyRelay := FALSE;
    bMotorRunning := FALSE;
    RETURN; (* Exit immediately when emergency condition exists *)
ELSE
    bEmergencyCondition := FALSE;
END_IF

(* Edge detection for buttons *)
bStartRisingEdge := StartButton AND NOT bStartButtonPrev;
bStopRisingEdge := StopButton AND NOT bStopButtonPrev;

(* Update previous button states for next scan *)
bStartButtonPrev := StartButton;
bStopButtonPrev := StopButton;

(* Main control logic when no emergency condition exists *)
IF NOT bEmergencyCondition THEN
    (* Motor start conditions *)
    IF NOT bMotorRunning THEN
        IF bStartRisingEdge OR MaterialInFeed THEN
            bMotorRunning := TRUE;
            MotorControl := TRUE;
            SafetyRelay := TRUE;
        END_IF
    END_IF

    (* Motor stop conditions *)
    IF bMotorRunning THEN
        IF bStopRisingEdge THEN
            bMotorRunning := FALSE;
            MotorControl := FALSE;
            SafetyRelay := FALSE;
        END_IF
    END_IF
END_IF

(* Ensure SafetyRelay is active when motor is running *)
IF bMotorRunning THEN
    SafetyRelay := TRUE;
END_IF

END_FUNCTION_BLOCK

FUNCTION_BLOCK WaterDesalination
VAR_INPUT
    StartButton : BOOL; (* Input for starting the desalination process *)
    StopButton : BOOL; (* Input for stopping the desalination process *)
    SalinitySensor : REAL; (* Input for salinity level measurement *)
END_VAR
VAR_OUTPUT
    SeawaterInletValve : BOOL; (* Output for seawater inlet valve control *)
    FreshwaterOutletValve : BOOL; (* Output for freshwater outlet valve control *)
    DesalinationInProgress : BOOL; (* Indicator for an ongoing desalination process *)
END_VAR
VAR
    MaxSalinity : REAL := 35.0; (* Maximum allowable salinity in ppm for freshwater *)
    SalinityControlSeconds : INT := 0; (* Timer for salinity control in seconds *)
    prevStartButton : BOOL := FALSE; (* Previous state of StartButton for edge detection *)
    prevStopButton : BOOL := FALSE; (* Previous state of StopButton for edge detection *)
END_VAR

(* Main control logic *)
(* Handle StartButton rising edge *)
IF StartButton AND NOT prevStartButton THEN
    (* Start process only if not already in progress *)
    IF NOT DesalinationInProgress THEN
        DesalinationInProgress := TRUE;
        SeawaterInletValve := TRUE;
        FreshwaterOutletValve := TRUE;
        SalinityControlSeconds := 0;
    END_IF;
END_IF;

(* Handle StopButton rising edge *)
IF StopButton AND NOT prevStopButton THEN
    DesalinationInProgress := FALSE;
    SeawaterInletValve := FALSE;
    FreshwaterOutletValve := FALSE;
    SalinityControlSeconds := 0;
END_IF;

(* Salinity monitoring and control - only when process is active *)
IF DesalinationInProgress THEN
    (* Increment timer *)
    SalinityControlSeconds := SalinityControlSeconds + 1;

    (* Check if 10 seconds have passed *)
    IF SalinityControlSeconds >= 10 THEN
        (* Compare salinity reading against maximum *)
        IF SalinitySensor > MaxSalinity THEN
            (* Close freshwater outlet valve if salinity is too high *)
            FreshwaterOutletValve := FALSE;
        ELSE
            (* Ensure freshwater outlet valve is open if salinity is acceptable *)
            FreshwaterOutletValve := TRUE;
        END_IF;

        (* Reset timer for next 10-second interval *)
        SalinityControlSeconds := 0;
    END_IF;
END_IF;

(* Update previous button states for next cycle *)
prevStartButton := StartButton;
prevStopButton := StopButton;

END_FUNCTION_BLOCK

FUNCTION_BLOCK SmartLockerControl
VAR_INPUT
    AccessCode : INT;    (* Input for user access code *)
    LockerNumber : INT;  (* Input for selected locker number *)
END_VAR
VAR_OUTPUT
    LockerOpen : BOOL;   (* Output to control locker door *)
END_VAR
VAR
    LockerStatus : ARRAY[1..10] OF BOOL;     (* Status of individual lockers: TRUE=locked, FALSE=empty *)
    LockerAccessCode : ARRAY[1..10] OF INT;  (* Locker access codes *)
    i : INT;                                  (* Loop counter *)
    bInitialized : BOOL := FALSE;            (* Initialization flag *)
END_VAR

(* Initialize arrays only once *)
IF NOT bInitialized THEN
    (* Initialize LockerAccessCode array *)
    LockerAccessCode[1] := 1234;
    LockerAccessCode[2] := 5678;
    LockerAccessCode[3] := 9876;
    LockerAccessCode[4] := 4321;
    LockerAccessCode[5] := 6543;
    LockerAccessCode[6] := 7890;
    LockerAccessCode[7] := 3456;
    LockerAccessCode[8] := 8765;
    LockerAccessCode[9] := 2345;
    LockerAccessCode[10] := 6789;

    (* Initialize LockerStatus array - all TRUE (locked) *)
    FOR i := 1 TO 10 DO
        LockerStatus[i] := TRUE;
    END_FOR;

    bInitialized := TRUE;
END_IF;

(* Reset LockerOpen output at the beginning of each cycle *)
LockerOpen := FALSE;

(* Validate LockerNumber input *)
IF (LockerNumber >= 1) AND (LockerNumber <= 10) THEN
    (* Check if access code matches *)
    IF AccessCode = LockerAccessCode[LockerNumber] THEN
        (* Grant access and update status *)
        LockerOpen := TRUE;
        LockerStatus[LockerNumber] := FALSE;  (* Set to empty/unlocked *)
    END_IF;
END_IF;

END_FUNCTION_BLOCK

FUNCTION_BLOCK SoilTestingDeviceControl
VAR_INPUT
    StartButton : BOOL; (* Input for starting the testing process *)
    SoilSampleDetected : BOOL; (* Input for detecting soil sample *)
END_VAR
VAR_OUTPUT
    NutrientPump : BOOL; (* Output to control nutrient pump *)
    pHAdjustmentPump : BOOL; (* Output to control pH adjustment pump *)
END_VAR
VAR
    pHSensorValue : REAL; (* Simulated pH sensor value *)
    NutrientSensorValue : REAL; (* Simulated nutrient sensor value *)
    TestingStatus : INT; (* Status: 0=Idle, 1=Testing, 2=Completed *)
    NutrientThreshold : REAL := 0.7; (* Nutrient level threshold for analysis *)
    pHThreshold : REAL := 6.5; (* pH level threshold for analysis *)
END_VAR

(* Main execution logic *)
CASE TestingStatus OF
    0: (* Idle state *)
        (* Initialize sensor values *)
        pHSensorValue := 7.0;
        NutrientSensorValue := 0.5;

        (* Ensure pumps are off *)
        NutrientPump := FALSE;
        pHAdjustmentPump := FALSE;

        (* Check for transition to Testing state *)
        IF StartButton THEN
            TestingStatus := 1;
        END_IF;

    1: (* Testing state *)
        (* Activate both pumps *)
        NutrientPump := TRUE;
        pHAdjustmentPump := TRUE;

        (* Update simulated sensor values with clamping *)
        (* Increment NutrientSensorValue by 0.1, max 0.9 *)
        NutrientSensorValue := NutrientSensorValue + 0.1;
        IF NutrientSensorValue > 0.9 THEN
            NutrientSensorValue := 0.9;
        END_IF;

        (* Decrement pHSensorValue by 0.5, min 4.0 *)
        pHSensorValue := pHSensorValue - 0.5;
        IF pHSensorValue < 4.0 THEN
            pHSensorValue := 4.0;
        END_IF;

        (* Check for completion criteria *)
        IF SoilSampleDetected THEN
            IF (NutrientSensorValue >= NutrientThreshold) AND (pHSensorValue <= pHThreshold) THEN
                TestingStatus := 2;
            END_IF;
        END_IF;

    2: (* Completed state *)
        (* Deactivate both pumps *)
        NutrientPump := FALSE;
        pHAdjustmentPump := FALSE;

        (* Remain in Completed state - no further action *)

    ELSE
        (* Handle unexpected state by resetting to Idle *)
        TestingStatus := 0;
END_CASE;

END_FUNCTION_BLOCK

FUNCTION_BLOCK AGVControlSystem
VAR_INPUT
    MaterialRequest : INT; (* 新的物料请求 *)
